import React, { createContext, useContext, useState, useEffect } from 'react'
import { api } from '../utils/api'

const AuthContext = createContext(null)

const TOKEN_KEY = 'token'
const USER_KEY = 'owner_user'

const saveToStorage = (token, user) => {
  localStorage.setItem(TOKEN_KEY, token)
  localStorage.setItem(USER_KEY, JSON.stringify(user))
  document.cookie = `token=${token}; path=/; max-age=${60 * 60 * 24 * 7}`
}

const clearStorage = () => {
  localStorage.removeItem(TOKEN_KEY)
  localStorage.removeItem(USER_KEY)
  document.cookie = 'token=; path=/; max-age=0'
}

const getStoredUser = () => {
  try {
    const raw = localStorage.getItem(USER_KEY)
    return raw ? JSON.parse(raw) : null
  } catch {
    return null
  }
}

export const AuthStoreProvider = ({ children }) => {
  const [user, setUser] = useState(null)
  const [isAuthenticated, setIsAuthenticated] = useState(false)
  const [isLoading, setIsLoading] = useState(true)

  useEffect(() => {
    const storedUser = getStoredUser()
    const token = localStorage.getItem(TOKEN_KEY)
    if (storedUser && token) {
      setUser(storedUser)
      setIsAuthenticated(true)
    }
    setIsLoading(false)
  }, [])

  const login = async (email, password) => {
    try {
      const data = await api.post('/api/auth/login', { email, password })

      if (!data.token) {
        throw new Error('No token received')
      }

      if (data.user.role !== 'owner') {
        throw new Error('Access denied — owner account required')
      }

      saveToStorage(data.token, data.user)
      setUser(data.user)
      setIsAuthenticated(true)
      return { success: true }
    } catch (err) {
      return { success: false, message: err.message }
    }
  }

  const logout = () => {
    clearStorage()
    setUser(null)
    setIsAuthenticated(false)
  }

  return (
    <AuthContext.Provider value={{ user, isAuthenticated, isLoading, login, logout }}>
      {children}
    </AuthContext.Provider>
  )
}

export const useAuth = () => {
  const ctx = useContext(AuthContext)
  if (!ctx) throw new Error('useAuth must be used within AuthStoreProvider')
  return ctx
}

export default AuthContext

import React, { createContext, useContext, useState } from 'react'

const NotificationContext = createContext(null)

const INITIAL_NOTIFICATIONS = [
  { id: '1', title: 'Low Stock Alert', subtitle: 'Pork Belly is below reorder point', timestamp: '2m ago', urgency: 'urgent', read: false },
  { id: '2', title: 'New Order', subtitle: 'Table 4 placed an order', timestamp: '8m ago', urgency: 'normal', read: false },
]

export function NotificationProvider({ children }) {
  const [notifications, setNotifications] = useState(INITIAL_NOTIFICATIONS)

  const unreadCount = notifications.filter(n => !n.read).length
  const markAllRead = () => setNotifications(ns => ns.map(n => ({ ...n, read: true })))
  const markRead = (id) => setNotifications(ns => ns.map(n => n.id === id ? { ...n, read: true } : n))
  const addNotification = (n) => setNotifications(ns => [n, ...ns])

  return (
    <NotificationContext.Provider value={{ notifications, unreadCount, markAllRead, markRead, addNotification }}>
      {children}
    </NotificationContext.Provider>
  )
}

export const useNotificationStore = () => useContext(NotificationContext)

import React, { createContext, useContext } from 'react';
import { useOrders } from '../hooks/useOrders';
import { useMenu } from '../hooks/useMenu';
import { useStock } from '../hooks/useStock';
import { useStaff } from '../hooks/useStaff';
import { useCustomers } from '../hooks/useCustomers';
import { useTables } from '../hooks/useTables';
import { usePromotions } from '../hooks/usePromotions';
import { useWaste } from '../hooks/useWaste';
import { useDashboard } from '../hooks/useDashboard';

export const StoreDataContext = createContext();

export const StoreDataProvider = ({ children }) => {
  const orders = useOrders();
  const menu = useMenu();
  const stock = useStock();
  const staff = useStaff();
  const customers = useCustomers();
  const tables = useTables();
  const promotions = usePromotions();
  const waste = useWaste();
  const dashboard = useDashboard();

  const value = {
    orders,
    menu,
    stock,
    staff,
    customers,
    tables,
    promotions,
    waste,
    dashboard
  };

  return (
    <StoreDataContext.Provider value={value}>
      {children}
    </StoreDataContext.Provider>
  );
};

export const useStoreData = () => {
  const context = useContext(StoreDataContext);
  if (!context) {
    throw new Error('useStoreData must be used within a StoreDataProvider');
  }
  return context;
};

import React, { createContext, useContext, useState } from 'react'

const UIContext = createContext(null)

export function UIProvider({ children }) {
  const [sidebarOpen, setSidebarOpen] = useState(false)
  const [activePopup, setActivePopup] = useState(null)
  const [tableView, setTableView] = useState('grid')

  const value = {
    sidebarOpen,
    setSidebarOpen,
    activePopup,
    tableView,
    toggleSidebar: () => setSidebarOpen(v => !v),
    openPopup: (name) => setActivePopup(name),
    closeAllPopups: () => setActivePopup(null),
    setTableView,
  }

  return <UIContext.Provider value={value}>{children}</UIContext.Provider>
}

export const useUIStore = () => useContext(UIContext)

import React, { useState, useMemo } from 'react'
import { Search, Filter, UserPlus } from 'lucide-react'
import { useCustomers } from '../hooks/useCustomers'
import CustomerRow from '../components/customers/CustomerRow'
import CustomerDetailPanel from '../components/customers/CustomerDetailPanel'

export default function Customers() {
  const { customers, isLoading } = useCustomers();
  const [search, setSearch] = useState('');
  const [selectedTier, setSelectedTier] = useState('All');
  const [selectedCustomer, setSelectedCustomer] = useState(null);

  const tiers = ['All', 'VIP', 'Gold', 'Silver', 'Basic'];

  const filteredCustomers = useMemo(() => {
    return customers.filter(c => {
      const matchesSearch = c.name.toLowerCase().includes(search.toLowerCase()) ||
                            c.phone.includes(search) ||
                            c.id.toLowerCase().includes(search.toLowerCase());
      const matchesTier = selectedTier === 'All' || c.tier === selectedTier;
      return matchesSearch && matchesTier;
    });
  }, [customers, search, selectedTier]);

  const vipCount = customers.filter(c => c.tier === 'VIP').length;

  return (
    <div className="flex flex-col min-h-full relative overflow-hidden">
      {/* Page Header */}
      <div className="pt-4 px-6 pb-[14px] bg-white border-b border-brand-border-outer flex items-center justify-between shrink-0">
        <div className="flex flex-col">
          <div className="text-[20px] font-bold text-brand-text-primary">Customer Management</div>
          <div className="text-[12px] text-brand-text-secondary mt-0.5">View member profiles, track spending, and manage loyalty points</div>
        </div>

        <div className="flex items-center gap-6 hidden md:flex">
          <div className="flex flex-col">
            <span className="text-[10px] text-brand-text-secondary uppercase tracking-wider font-semibold">Total Members</span>
            <div className="text-[18px] font-bold text-brand-text-primary">{customers.length}</div>
          </div>
          <div className="w-[1px] h-8 bg-brand-border-inner"></div>
          <div className="flex flex-col">
            <span className="text-[10px] text-brand-text-secondary uppercase tracking-wider font-semibold">VIP Members</span>
            <div className="text-[18px] font-bold text-brand-success">{vipCount}</div>
          </div>
          <div className="w-[1px] h-8 bg-brand-border-inner"></div>
          <button className="flex items-center gap-1.5 px-4 py-2 bg-brand-text-dark text-white rounded-lg text-[13px] font-bold shadow-sm hover:bg-brand-text-dark/90 transition-colors">
            <UserPlus size={16} />
            Add New Member
          </button>
        </div>
      </div>

      {/* Toolbar */}
      <div className="p-6 pb-0 flex flex-col md:flex-row gap-4">
        <div className="flex-1 relative">
          <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-brand-text-tertiary" />
          <input
            type="text"
            placeholder="Search by name, phone, or ID..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2 bg-white border border-brand-border-outer rounded-xl text-[14px] text-brand-text-primary focus:border-brand-text-tertiary outline-none transition-all shadow-sm"
          />
        </div>

        <div className="flex items-center gap-2 overflow-x-auto no-scrollbar">
          {tiers.map(tier => (
            <button
              key={tier}
              onClick={() => setSelectedTier(tier)}
              className={`px-4 py-2 rounded-full text-[12px] font-medium border transition-all whitespace-nowrap ${
                selectedTier === tier
                  ? 'bg-brand-text-dark border-brand-text-dark text-white shadow-md'
                  : 'bg-white border-brand-border-outer text-brand-text-secondary hover:bg-brand-hover-row'
              }`}
            >
              {tier === 'All' ? 'All Tiers' : `${tier} Tier`}
            </button>
          ))}
        </div>
      </div>

      {/* Main Table Container */}
      <div className="p-6 flex-1 overflow-hidden">
        <div className="bg-white border border-brand-border-outer rounded-2xl shadow-sm overflow-hidden flex flex-col h-full">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-brand-subheader border-b border-brand-border-inner">
                  <th className="py-3 px-4 text-[11px] font-bold text-brand-text-secondary uppercase tracking-wider">Member</th>
                  <th className="py-3 px-4 text-[11px] font-bold text-brand-text-secondary uppercase tracking-wider">Contact</th>
                  <th className="py-3 px-4 text-[11px] font-bold text-brand-text-secondary uppercase tracking-wider">Tier</th>
                  <th className="py-3 px-4 text-[11px] font-bold text-brand-text-secondary uppercase tracking-wider">Points</th>
                  <th className="py-3 px-4 text-[11px] font-bold text-brand-text-secondary uppercase tracking-wider">Total Spent</th>
                  <th className="py-3 px-4 text-[11px] font-bold text-brand-text-secondary uppercase tracking-wider text-right">Last Visit</th>
                </tr>
              </thead>
              <tbody>
                {isLoading ? (
                  <tr>
                    <td colSpan={6} className="py-20 text-center text-brand-text-tertiary">Loading members...</td>
                  </tr>
                ) : filteredCustomers.length > 0 ? (
                  filteredCustomers.map(customer => (
                    <CustomerRow
                      key={customer.id}
                      customer={customer}
                      onClick={(c) => setSelectedCustomer(c)}
                    />
                  ))
                ) : (
                  <tr>
                    <td colSpan={6} className="py-20 text-center text-brand-text-tertiary">No members found matching your criteria.</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>

          <div className="px-4 py-3 border-t border-brand-border-inner bg-brand-hover-row flex items-center justify-between text-[11px] text-brand-text-secondary">
            <span>Showing {filteredCustomers.length} of {customers.length} total members</span>
            <div className="flex items-center gap-1">
              <button className="px-2 py-1 border border-brand-border-outer rounded bg-white hover:bg-brand-sidebar transition-colors">Previous</button>
              <button className="px-2 py-1 border border-brand-border-outer rounded bg-white hover:bg-brand-sidebar transition-colors">Next</button>
            </div>
          </div>
        </div>
      </div>

      {/* Slide-in Detail Panel */}
      <div className={`fixed inset-0 z-[190] transition-opacity duration-300 ${selectedCustomer ? 'bg-[#1A2333]/20 opacity-100 visible' : 'bg-[#1A2333]/0 opacity-0 invisible'}`} onClick={() => setSelectedCustomer(null)}></div>
      <div className={`fixed inset-y-0 right-0 z-[200] transform transition-transform duration-300 ease-in-out ${selectedCustomer ? 'translate-x-0' : 'translate-x-full'}`}>
        <CustomerDetailPanel
          customer={selectedCustomer}
          onClose={() => setSelectedCustomer(null)}
        />
      </div>
    </div>
  )
}

import React, { useState, useMemo } from 'react'
import { Search, Plus, Filter, ArrowUpDown, ChevronDown } from 'lucide-react'
import { useStoreData } from '../context/StoreDataContext'
import OrderRow from '../components/orders/OrderRow'

export default function Orders() {
  const { orders: ordersStore } = useStoreData();
  const { orders, isLoading, updateStatus } = ordersStore;
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [typeFilter, setOrderTypeFilter] = useState('All');

  const filteredOrders = useMemo(() => {
    return orders.filter(order => {
      const matchesSearch = order.id.includes(search);
      const matchesStatus = statusFilter === 'All' || order.status === statusFilter;
      const matchesType = typeFilter === 'All' || order.type === typeFilter;
      return matchesSearch && matchesStatus && matchesType;
    });
  }, [orders, search, statusFilter, typeFilter]);

  const statuses = ['All', 'New', 'Cooking', 'Ready', 'Paid', 'Delivered', 'Cancelled'];
  const types = ['All', 'In-Restaurant', 'Take Away', 'Delivery'];

  const stats = useMemo(() => {
    return {
      new: orders.filter(o => o.status === 'New').length,
      cooking: orders.filter(o => o.status === 'Cooking').length,
      ready: orders.filter(o => o.status === 'Ready').length,
    };
  }, [orders]);

  return (
    <div className="flex flex-col min-h-full">
      {/* Page Header */}
      <div className="pt-4 px-6 pb-[14px] bg-white border-b border-brand-border-outer flex items-center justify-between shrink-0">
        <div className="flex flex-col">
          <div className="text-[20px] font-bold text-brand-text-primary">Order Management</div>
          <div className="text-[12px] text-brand-text-secondary mt-0.5">Track real-time orders, manage kitchen flow and delivery status</div>
        </div>

        <div className="flex items-center gap-6 hidden md:flex">
          <div className="flex flex-col">
            <span className="text-[10px] text-brand-text-secondary uppercase tracking-wider font-semibold">New Orders</span>
            <div className="text-[18px] font-bold text-brand-danger">{stats.new}</div>
          </div>
          <div className="w-[1px] h-8 bg-brand-border-inner"></div>
          <div className="flex flex-col">
            <span className="text-[10px] text-brand-text-secondary uppercase tracking-wider font-semibold">In Kitchen</span>
            <div className="text-[18px] font-bold text-brand-warning-text">{stats.cooking}</div>
          </div>
          <div className="w-[1px] h-8 bg-brand-border-inner"></div>
          <div className="flex flex-col">
            <span className="text-[10px] text-brand-text-secondary uppercase tracking-wider font-semibold">Ready to Serve</span>
            <div className="text-[18px] font-bold text-brand-success">{stats.ready}</div>
          </div>
          <div className="w-[1px] h-8 bg-brand-border-inner"></div>
          <button className="flex items-center gap-1.5 px-4 py-2 bg-brand-text-dark text-white rounded-lg text-[13px] font-bold shadow-sm hover:bg-brand-text-dark/90 transition-colors">
            <Plus size={16} />
            Create New Order
          </button>
        </div>
      </div>

      {/* Toolbar */}
      <div className="p-6 pb-4 flex flex-col gap-4">
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
          <div className="flex flex-wrap items-center gap-2">
            <div className="relative">
              <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-brand-text-tertiary" />
              <input
                type="text"
                placeholder="Search Order ID..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="pl-9 pr-4 py-1.5 bg-white border border-brand-border-outer rounded-lg text-[13px] text-brand-text-primary focus:border-brand-text-tertiary outline-none transition-all shadow-sm w-48"
              />
            </div>

            <div className="h-8 w-[1px] bg-brand-border-inner mx-1 hidden sm:block"></div>

            <div className="flex items-center gap-2 bg-brand-sidebar p-1 rounded-lg border border-brand-border-inner">
              {types.map(t => (
                <button
                  key={t}
                  onClick={() => setOrderTypeFilter(t)}
                  className={`px-3 py-1 rounded-md text-[11px] font-medium transition-all ${
                    typeFilter === t
                      ? 'bg-white shadow-sm text-brand-text-primary'
                      : 'text-brand-text-secondary hover:text-brand-text-primary'
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>

          <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1 w-full lg:w-auto">
            <span className="text-[11px] font-bold text-brand-text-tertiary uppercase tracking-widest mr-1">Status:</span>
            {statuses.map(s => (
              <button
                key={s}
                onClick={() => setStatusFilter(s)}
                className={`px-3 py-1 rounded-full text-[11px] font-medium border transition-all whitespace-nowrap ${
                  statusFilter === s
                    ? 'bg-brand-text-dark border-brand-text-dark text-white shadow-md'
                    : 'bg-white border-brand-border-outer text-brand-text-secondary hover:bg-brand-hover-row'
                }`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Main Table */}
      <div className="px-6 flex-1 overflow-hidden pb-6">
        <div className="bg-white border border-brand-border-outer rounded-2xl shadow-sm overflow-hidden flex flex-col h-full">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-brand-subheader border-b border-brand-border-inner">
                  <th className="py-3 px-6 text-[11px] font-bold text-brand-text-secondary uppercase tracking-wider">Order ID</th>
                  <th className="py-3 px-6 text-[11px] font-bold text-brand-text-secondary uppercase tracking-wider">Type</th>
                  <th className="py-3 px-6 text-[11px] font-bold text-brand-text-secondary uppercase tracking-wider">Items</th>
                  <th className="py-3 px-6 text-[11px] font-bold text-brand-text-secondary uppercase tracking-wider text-right">Total</th>
                  <th className="py-3 px-6 text-[11px] font-bold text-brand-text-secondary uppercase tracking-wider text-center">Status</th>
                  <th className="py-3 px-6 text-[11px] font-bold text-brand-text-secondary uppercase tracking-wider text-right">Quick Action</th>
                </tr>
              </thead>
              <tbody>
                {isLoading ? (
                  <tr>
                    <td colSpan={6} className="py-20 text-center">
                      <div className="flex flex-col items-center gap-2 text-brand-text-tertiary">
                        <div className="w-6 h-6 border-2 border-brand-text-tertiary border-t-transparent rounded-full animate-spin"></div>
                        <span className="text-[13px]">Loading orders...</span>
                      </div>
                    </td>
                  </tr>
                ) : filteredOrders.length > 0 ? (
                  filteredOrders.map(order => (
                    <OrderRow
                      key={order.id}
                      order={order}
                      onUpdateStatus={(id, status) => updateStatus({ id, status })}
                    />
                  ))
                ) : (
                  <tr>
                    <td colSpan={6} className="py-32 text-center text-brand-text-tertiary">
                      <div className="flex flex-col items-center gap-3">
                        <Filter size={40} className="opacity-20" />
                        <div className="flex flex-col">
                          <span className="text-[14px] font-bold text-brand-text-primary">No orders found</span>
                          <span className="text-[12px]">Try adjusting your search or filters</span>
                        </div>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>

          <div className="mt-auto px-6 py-3 border-t border-brand-border-inner bg-brand-hover-row flex items-center justify-between text-[11px] text-brand-text-secondary">
            <span>Showing {filteredOrders.length} of {orders.length} total orders</span>
            <div className="flex items-center gap-4">
              <div className="flex items-center gap-2">
                <span>Lines per page:</span>
                <select className="bg-transparent border-none outline-none font-bold text-brand-text-primary cursor-pointer">
                  <option>10</option>
                  <option>25</option>
                  <option>50</option>
                </select>
              </div>
              <div className="flex items-center gap-1">
                <button className="px-2 py-1 border border-brand-border-outer rounded bg-white hover:bg-brand-sidebar transition-colors disabled:opacity-50" disabled>Previous</button>
                <button className="px-2 py-1 border border-brand-border-outer rounded bg-white hover:bg-brand-sidebar transition-colors disabled:opacity-50" disabled>Next</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

import React, { useState, useMemo } from 'react'
import { Search, Plus, Filter, Zap, Target } from 'lucide-react'
import { usePromotions } from '../hooks/usePromotions'
import { getPromoStatus } from '../utils/getPromoStatus'
import PromotionRow from '../components/promotions/PromotionRow'
import { formatTHB } from '../utils/format'

export default function Promotions() {
  const { promotions, isLoading, updatePromotion } = usePromotions();
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');

  const filteredPromotions = useMemo(() => {
    return promotions.filter(promo => {
      const matchesSearch = promo.name.toLowerCase().includes(search.toLowerCase()) ||
                            promo.code.toLowerCase().includes(search.toLowerCase());
      const status = getPromoStatus(promo.startDate, promo.endDate);
      const matchesStatus = statusFilter === 'All' || status === statusFilter;
      return matchesSearch && matchesStatus;
    });
  }, [promotions, search, statusFilter]);

  const stats = useMemo(() => {
    const active = promotions.filter(p => getPromoStatus(p.startDate, p.endDate) === 'Active' && p.active).length;
    const totalSavings = promotions.reduce((sum, p) => sum + p.totalAmountSaved, 0);
    return { active, totalSavings };
  }, [promotions]);

  const filterOptions = ['All', 'Active', 'ExpSoon', 'Scheduled', 'Expired'];

  return (
    <div className="flex flex-col min-h-full">
      {/* Page Header */}
      <div className="pt-4 px-6 pb-[14px] bg-white border-b border-brand-border-outer flex items-center justify-between shrink-0">
        <div className="flex flex-col">
          <div className="text-[20px] font-bold text-brand-text-primary">Marketing & Promotions</div>
          <div className="text-[12px] text-brand-text-secondary mt-0.5">Manage discounts, seasonal offers and track campaign performance</div>
        </div>

        <div className="flex items-center gap-6 hidden md:flex">
          <div className="flex flex-col">
            <div className="flex items-center gap-1.5">
              <span className="text-[10px] text-brand-text-secondary uppercase tracking-wider font-semibold">Active Campaigns</span>
              <Zap size={10} className="text-brand-success" />
            </div>
            <div className="text-[18px] font-bold text-brand-text-primary">{stats.active}</div>
          </div>
          <div className="w-[1px] h-8 bg-brand-border-inner"></div>
          <div className="flex flex-col">
            <div className="flex items-center gap-1.5">
              <span className="text-[10px] text-brand-text-secondary uppercase tracking-wider font-semibold">Customer Savings</span>
              <Target size={10} className="text-brand-success" />
            </div>
            <div className="text-[18px] font-bold text-brand-success">{formatTHB(stats.totalSavings)}</div>
          </div>
          <div className="w-[1px] h-8 bg-brand-border-inner"></div>
          <button className="flex items-center gap-1.5 px-4 py-2 bg-brand-text-dark text-white rounded-lg text-[13px] font-bold shadow-sm hover:bg-brand-text-dark/90 transition-colors">
            <Plus size={16} />
            Create Campaign
          </button>
        </div>
      </div>

      {/* Toolbar */}
      <div className="p-6 pb-4 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1 w-full md:w-auto">
          {filterOptions.map(opt => (
            <button
              key={opt}
              onClick={() => setStatusFilter(opt)}
              className={`px-4 py-1.5 rounded-full text-[12px] font-medium border transition-all whitespace-nowrap ${
                statusFilter === opt
                  ? 'bg-brand-text-dark border-brand-text-dark text-white shadow-md'
                  : 'bg-white border-brand-border-outer text-brand-text-secondary hover:bg-brand-hover-row'
              }`}
            >
              {opt}
            </button>
          ))}
