import { createContext, useContext, useState, useEffect, useMemo } from "react";
import { MENU } from "../assets/menuData";

export const ShopContext = createContext();

export const ShopProvider = ({ children }) => {
  // --- Cart State ---
  const [cart, setCart] = useState(() => {
    const savedCart = localStorage.getItem("crispyCart");
    return savedCart ? JSON.parse(savedCart) : [];
  });

  // --- UI Global State ---
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isLoginModalOpen, setIsLoginModalOpen] = useState(false);
  const [toastMsg, setToastMsg] = useState("");

  // --- Branch State ---
  const [selectedBranch, setSelectedBranch] = useState(() =>
    localStorage.getItem("selectedBranch")
  );

  // Sync cart to localStorage
  useEffect(() => {
    localStorage.setItem("crispyCart", JSON.stringify(cart));
  }, [cart]);

  // Derived state
  const cartCount = useMemo(() => 
    cart.reduce((sum, item) => sum + item.qty, 0), 
  [cart]);

  const updateCartQty = (id, delta) => {
    setCart((prev) =>
      prev
        .map((item) => {
          if (item.id === id) return { ...item, qty: item.qty + delta };
          return item;
        })
        .filter((item) => item.qty > 0)
    );
  };

  const addToCart = (id, qty = 1) => {
    setCart((prev) => {
      const menuItem = MENU.find((m) => m.id === id);
      if (!menuItem) {
        console.warn(`Menu item with id ${id} not found`);
        return prev;
      }

      const existing = prev.find((item) => item.id === id);
      if (existing) {
        return prev.map((item) =>
          item.id === id ? { ...item, qty: item.qty + qty } : item
        );
      }

      // Store full menu item data with qty
      return [
        ...prev,
        {
          id,
          name: menuItem.name,
          price: menuItem.price,
          img: menuItem.img,
          qty,
        },
      ];
    });
  };

  const showToast = (msg, duration = 3000) => {
    setToastMsg(msg);
    setTimeout(() => setToastMsg(""), duration);
  };

  const selectBranch = (branchId) => {
    setSelectedBranch(branchId);
    localStorage.setItem("selectedBranch", branchId);
  };

  const value = {
    cart,
    setCart,
    cartCount,
    updateCartQty,
    addToCart,
    isCartOpen,
    setIsCartOpen,
    isLoginModalOpen,
    setIsLoginModalOpen,
    toastMsg,
    showToast,
    selectedBranch,
    selectBranch
  };

  return <ShopContext.Provider value={value}>{children}</ShopContext.Provider>;
};

export const useShop = () => {
  const context = useContext(ShopContext);
  if (!context) {
    throw new Error("useShop must be used within a ShopProvider");
  }
  return context;
};

// เก็บข้อมูลตะกร้าสินค้า/ออเดอร์
import { useState, useCallback, useContext, useEffect } from "react";
import { orders as initialMockOrders } from "../../assets/order";
import { OrdersContext } from "./OrdersContext";
import { orderService } from "../../services/orderService";
import { ShopContext } from "../ShopProvider";

export const OrdersProvider = ({ children }) => {
  const { cart } = useContext(ShopContext);

  const [orderList, setOrderList] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [currentOrder, setCurrentOrder] = useState(null);

  // Sync with ShopContext cart
  useEffect(() => {
    if (cart && cart.length > 0) {
      // Create a single active order from cart items
      const activeOrder = {
        orderId: "current-cart",
        orderList: cart.map(item => ({
          ...item,
          quantity: item.qty, // Map qty to quantity for consistency
          id: item.id
        }))
      };
      setOrderList([activeOrder]);
    } else {
      setOrderList([]);
    }
  }, [cart]);

  // Update single order in list
  const updateOrder = useCallback((orderId, updates) => {
    setOrderList((prev) =>
      prev.map((order) =>
        order.orderId === orderId ? { ...order, ...updates } : order
      )
    );
  }, []);

  // Remove order from list
  const removeOrder = useCallback((orderId) => {
    setOrderList((prev) => prev.filter((order) => order.orderId !== orderId));
  }, []);

  // Update item quantity in order
  const updateItemQty = useCallback((orderId, itemId, newQty) => {
    setOrderList((prev) =>
      prev.map((order) => {
        if (order.orderId !== orderId) return order;
        const key = order.List ? "List" : "orderList";
        return {
          ...order,
          [key]: order[key].map((item) =>
            item.id === itemId ? { ...item, quantity: Math.max(1, newQty) } : item
          ),
        };
      })
    );
  }, []);

  // Remove item from order
  const removeItem = useCallback((orderId, itemId) => {
    setOrderList((prev) =>
      prev
        .map((order) => {
          if (order.orderId !== orderId) return order;
          const key = order.List ? "List" : "orderList";
          return {
            ...order,
            [key]: order[key].filter((item) => item.id !== itemId),
          };
        })
        .filter((order) => {
          const items = order.List || order.orderList || [];
          return items.length > 0;
        })
    );
  }, []);

  // Clear all orders
  const clearCart = useCallback(() => {
    setOrderList([]);
  }, []);

  // Submit order to API
  const submitOrder = useCallback(async (orderData) => {
    setLoading(true);
    setError(null);
    try {
      const response = await orderService.submitOrder(orderData.orderId, orderData);
      setCurrentOrder(response);
      return response;
    } catch (err) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  }, []);

  // Legacy handler for compatibility
  const ordersListHandler = (e) => {
    setOrderList(e);
  };

  const value = {
    orderList,
    setOrderList,
    ordersListHandler,
    currentOrder,
    setCurrentOrder,
    loading,
    error,
    updateOrder,
    removeOrder,
    updateItemQty,
    removeItem,
    clearCart,
    submitOrder,
  };

  return (
    <OrdersContext.Provider value={value}>
      {children}
    </OrdersContext.Provider>
  );
};

// src/pages/Login.jsx
import React, { useContext, useState, useEffect } from "react";
import { UserContext } from "../context/userContext/UserContext";
import { useNavigate } from "react-router-dom";
import { loginAPI } from "../services/authService";
import LoginCard from "../component/LoginCard";

export default function Login() {
  const navigate = useNavigate();
  const { myUserInfo, setMyUserInfo } = useContext(UserContext);

  // --- States ---
  const [loginText, setLoginText] = useState("");
  const [inputEmail, setInputEmail] = useState("");
  const [inputPassword, setInputPassword] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  // ป้องกันกรณีล็อกอินอยู่แล้วแต่ยังพยายามเข้าหน้า Login
  useEffect(() => {
    if (myUserInfo) {
      // ถ้าเป็นลูกค้าให้ไปหน้าเมนู ถ้าเป็นบทบาทอื่นให้ไปหน้า Dashboard ของตัวเอง
      if (myUserInfo.role === "customer") navigate("/menu");
      else if (myUserInfo.role === "cook") navigate("/cookBoard");
      else if (myUserInfo.role === "cashier") navigate("/cashier/orders");
    }
  }, [myUserInfo, navigate]);

  const checkLogin = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    setLoginText("");

    try {
      const user = await loginAPI(inputEmail, inputPassword);
      setMyUserInfo(user);
      // การนำทาง (Navigation) จะถูกจัดการโดย useEffect ด้านบนเมื่อ myUserInfo เปลี่ยนแปลง
    } catch (error) {
      setLoginText(error.message);
    } finally {
      setIsLoading(false);
    }
  };

  const logoutBtn = (e) => {
    e.preventDefault();
    setMyUserInfo(null);
  };

  const redirectAfterLogin = (user) => {
    if (user.role === "customer") {
      // ถ้าลูกค้ากด Login มาจากหน้าไหน (เช่น ตะกร้า) ให้เด้งกลับไปที่นั่น
      // หรือถ้าไม่มีข้อมูล ให้ไปหน้า /menu เป็นพื้นฐาน
      const lastPath = localStorage.getItem("lastPath") || "/menu";
      navigate(lastPath);
    } else if (user.role === "cook") {
      navigate("/cookBoard");
    } else if (user.role === "cashier") {
      navigate("/cashier/orders");
    } else if (user.role === "rider") {
      navigate("/rider-dashboard");
    } else if (user.role === "owner") {
      navigate("/owner-dashboard");
    }
  };

  return (
    <div className="min-h-[calc(100vh-80px)] bg-[#eeeeee] flex items-center justify-center p-6 font-['IBM_Plex_Sans_Thai'] text-[#242424]">
      <div className="max-w-6xl w-full flex flex-col lg:flex-row items-center gap-12 lg:gap-20">
        {/* === ฝั่งซ้าย: โซน Graphic (SFC Style) === */}
        <div className="hidden lg:flex flex-1 flex-col justify-center items-center">
          <div className="w-full aspect-square bg-[#e4002b] rounded-[3rem] border-4 border-[#242424] flex items-center justify-center relative overflow-hidden transition-transform duration-500">
            <img
              src="/images/login-left.png"
              className="w-full h-full object-cover"
            />
          </div>
        </div>

        {/* === ฝั่งขวา: โซนฟอร์ม / สถานะการล็อกอิน === */}
        <div className="flex-1 flex justify-center w-full">
          {!myUserInfo ? (
            <LoginCard
              inputEmail={inputEmail}
              setInputEmail={setInputEmail}
              inputPassword={inputPassword}
              setInputPassword={setInputPassword}
              isLoading={isLoading}
              loginText={loginText}
              onSubmit={checkLogin}
            />
          ) : (
            // การ์ดสถานะ "YOU'RE IN"
            <div className="bg-white border-4 border-[#242424] shadow-[16px_16px_0_#242424] rounded-4xl p-10 md:p-12 w-full max-w-sm text-center">
              <div className="w-24 h-24 bg-[#DC5F00] border-4 border-[#242424] rounded-full mx-auto mb-6 flex items-center justify-center shadow-[6px_6px_0_#242424]"></div>

              <h2 className="font-['Bebas_Neue'] text-5xl mb-6 tracking-tight text-[#242424]">
                YOU'RE IN!
              </h2>

              <div className="bg-[#eeeeee] border-2 border-[#242424] rounded-2xl p-5 mb-8 text-left space-y-3">
                <div>
                  <p className="font-bold text-[10px] text-gray-500 uppercase tracking-widest">
                    Active Role
                  </p>
                  <p className="font-black text-2xl text-[#e4002b] font-['Bebas_Neue'] uppercase leading-none">
                    {myUserInfo.role}
                  </p>
                </div>
                <div className="pt-2 border-t border-gray-300">
                  <p className="font-bold text-[10px] text-gray-500 uppercase tracking-widest">
                    Account Name
                  </p>
                  <p className="font-black text-xl leading-none">
                    {myUserInfo.name}
                  </p>
                </div>
              </div>

              <button
                onClick={logoutBtn}
                className="w-full bg-[#242424] text-white font-['Bebas_Neue'] text-2xl tracking-widest py-4 rounded-xl border-2 border-[#242424] shadow-[6px_6px_0_#e4002b] transition-all duration-300 hover:translate-y-1 hover:shadow-[2px_2px_0_#e4002b] active:scale-95"
              >
                LOG OUT
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// src/pages/customer/MenuPage.jsx
import React, { useState, useEffect, useContext } from "react";
import { NavLink, useNavigate, useSearchParams } from "react-router-dom";
import {
  HandFist,
  ShoppingCart,
  ArrowRight,
  CheckCircle,
  MapPin,
} from "lucide-react";
import MenuCard from "../../component/customer/MenuCard";
import CartSidebar from "../../component/customer/CartSidebar";
import { OrdersContext } from "../../context/ordersContext/OrdersContext";
import ProductModal from "../../component/customer/ProductModal";
import LoginModal from "../../component/LoginModal";
import { useShop } from "../../context/ShopProvider";
import {
  PROMOTIONS,
  MENU,
  AUTOPLAY_INTERVAL_MS,
  TOAST_DURATION_MS,
} from "../../assets/menuData";

const MenuPage = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const {
    cart,
    cartCount,
    addToCart: shopAddToCart,
    updateCartQty,
    isCartOpen,
    setIsCartOpen,
    isLoginModalOpen,
    setIsLoginModalOpen,
    toastMsg,
    showToast,
    selectedBranch,
    selectBranch,
  } = useShop();

  // --- Local UI States ---
  const [activeTab, setActiveTab] = useState("all");
  const [currentSlide, setCurrentSlide] = useState(0);
  const [selectedItem, setSelectedItem] = useState(null);
  const [isBranchModalOpen, setIsBranchModalOpen] = useState(false);
  const [pendingAction, setPendingAction] = useState(null);

  const totalItems = cartCount;

  // เช็ค URL เมื่อมีการเปลี่ยนแปลง
  useEffect(() => {
    const currentTab = searchParams.get("tab");
    if (currentTab) setActiveTab(currentTab);

    if (searchParams.get("cart") === "open") {
      setIsCartOpen(true);
      searchParams.delete("cart");
      setSearchParams(searchParams, { replace: true });
    }
  }, [searchParams, setSearchParams, setIsCartOpen]);

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % PROMOTIONS.length);
    }, AUTOPLAY_INTERVAL_MS);
    return () => clearInterval(timer);
  }, []);

  // --- Functions ---
  const handleTabChange = (tabId) => {
    setActiveTab(tabId);
    setSearchParams(tabId === "all" ? {} : { tab: tabId });
  };

  const handleSelectBranch = (branchId) => {
    selectBranch(branchId);
    setIsBranchModalOpen(false);

    if (pendingAction) {
      if (pendingAction.type === "ADD") {
        executeAddToCart(
          pendingAction.item.id,
          pendingAction.item.name,
          pendingAction.qty,
        );
      } else if (pendingAction.type === "VIEW") {
        setSelectedItem(pendingAction.item);
      }
      setPendingAction(null);
    }
  };

  const checkBranchBeforeAction = (type, item, qty = 1) => {
    if (!selectedBranch) {
      setPendingAction({ type, item, qty });
      setIsBranchModalOpen(true);
    } else {
      if (type === "ADD") {
        executeAddToCart(item.id, item.name, qty);
      } else if (type === "VIEW") {
        setSelectedItem(item);
      }
    }
  };

  // ฟังก์ชันใส่ตะกร้า
  const executeAddToCart = (id, name, qty = 1) => {
    shopAddToCart(id, qty);
    showToast(`Added: ${name}`);
  };

  const handleUpdateQty = (id, delta) => {
    updateCartQty(id, delta);
  };

  const filteredMenu =
    activeTab === "all" ? MENU : MENU.filter((m) => m.cat === activeTab);

  const totalPrice = cart.reduce((sum, item) => {
    return sum + ((item.price || 0) * item.qty);
  }, 0);

  return (
    <div className="min-h-screen bg-[#eeeeee] font-['IBM_Plex_Sans_Thai'] text-[#242424]">
      {/* Branch Selector Modal */}
      {isBranchModalOpen && (
        <div className="fixed inset-0 z-9999 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-3xl max-w-md w-full border-4 border-[#242424] shadow-[12px_12px_0_#242424] text-center relative">
            <button
              onClick={() => {
                setIsBranchModalOpen(false);
                setPendingAction(null);
              }}
              className="absolute top-4 right-4 text-gray-500 hover:text-black"
            >
              ✕
            </button>
            <div className="w-16 h-16 bg-[#e4002b] rounded-full flex items-center justify-center mx-auto mb-6 shadow-md">
              <MapPin size={32} color="white" />
            </div>
            <h2 className="font-['Bebas_Neue'] text-4xl mb-2">
              CHOOSE YOUR STORE
            </h2>
            <p className="text-gray-600 mb-8">
              Please select a branch before ordering.
            </p>
            <div className="space-y-4">
              <button
                onClick={() => handleSelectBranch("branch1")}
                className="w-full p-4 border-2 border-[#242424] rounded-xl font-bold hover:bg-[#e4002b] hover:text-white transition-colors flex justify-between items-center"
              >
                <span>Asok Branch (HQ)</span>
                <span className="text-sm bg-[#242424] text-white px-2 py-1 rounded">
                  OPEN
                </span>
              </button>
              <button
                disabled
                className="w-full p-4 border-2 border-gray-300 text-gray-400 rounded-xl font-bold bg-gray-100 flex justify-between items-center cursor-not-allowed"
              >
                <span>Siam Branch</span>
                <span className="text-sm bg-gray-300 text-gray-500 px-2 py-1 rounded">
                  COMING SOON
                </span>
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Main Layout */}
      <div className="flex flex-col md:flex-row relative">
        <aside className="relative w-full h-100 md:w-105 md:shrink-0 md:sticky md:top-20 md:h-[calc(100vh-80px)] bg-[#242424] overflow-hidden z-10">
          {PROMOTIONS.map((promo, i) => (
            <div
              key={promo.id}
              className={`absolute inset-0 flex flex-col justify-end transition-opacity duration-500 ${i === currentSlide ? "opacity-100 z-10" : "opacity-0 z-0"}`}
            >
              <div className="absolute inset-0">
                <img
                  src={promo.img}
                  alt={promo.title}
                  className="w-full h-full object-cover"
                  onError={(e) => {
                    e.target.src =
                      "https://placehold.co/600x800/242424/e4002b?text=PROMO";
                  }}
                />
                <div className="absolute inset-0 bg-linear-to-t from-black/95 via-black/50 to-transparent" />
              </div>
              <div className="relative z-20 p-8 pb-16 text-white">
                <span className="text-[#e4002b] font-bold text-sm tracking-[3px] shadow-sm">
                  {promo.tag}
                </span>
                <h2 className="font-['Bebas_Neue'] text-5xl leading-[0.9] my-2 drop-shadow-md">
                  {promo.title}
                </h2>
                <div className="font-['Bebas_Neue'] text-4xl mb-4">
                  {promo.price}
                </div>
                <button
                  onClick={() => alert("โปรโมชั่นคอมโบเซตจะมาในเฟสถัดไปครับ!")}
                  className="bg-[#e4002b] text-white px-8 py-3 rounded-md font-bold font-['Bebas_Neue'] text-xl hover:bg-white hover:text-black transition shadow-lg cursor-pointer"
                >
                  ORDER NOW
                </button>
              </div>
            </div>
          ))}
          <div className="absolute bottom-5 left-0 w-full flex justify-center gap-3 z-30">
            {PROMOTIONS.map((_, i) => (
              <button
                key={i}
                onClick={() => setCurrentSlide(i)}
                className={`w-2.5 h-2.5 rounded-full transition-all duration-300 ${i === currentSlide ? "bg-[#e4002b] scale-150" : "bg-white/40"} cursor-pointer`}
              />
            ))}
          </div>
        </aside>

        <main className="flex-1 p-6 md:p-12 pb-32 md:pb-12 z-0">
          <div className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-4">
            <div>
              <span className="text-[#e4002b] font-black tracking-widest text-sm uppercase">
                Explore Flavors
              </span>
              <h2 className="text-5xl font-black font-['Bebas_Neue'] mt-2 text-[#242424]">
                SERIOUS SELECTIONS
              </h2>
            </div>
            {selectedBranch ? (
              <button
                onClick={() => setIsBranchModalOpen(true)}
                className="flex items-center gap-2 bg-white border-2 border-[#242424] px-4 py-2 rounded-lg shadow-[4px_4px_0_#242424] hover:bg-gray-100 transition-colors text-sm font-bold cursor-pointer"
              >
                <MapPin size={16} className="text-[#e4002b]" /> Store:{" "}
                {selectedBranch === "branch1" ? "Asok (HQ)" : selectedBranch}
              </button>
            ) : (
              <button
                onClick={() => setIsBranchModalOpen(true)}
                className="flex items-center gap-2 bg-[#e4002b] text-white border-2 border-[#242424] px-4 py-2 rounded-lg shadow-[4px_4px_0_#242424] hover:bg-black transition-colors text-sm font-bold animate-pulse cursor-pointer"
              >
                <MapPin size={16} /> Choose Store
              </button>
            )}
          </div>

          <div
            className="flex gap-3 mb-8 overflow-x-auto pb-2"
            style={{ scrollbarWidth: "none" }}
          >
            {[
              { id: "all",      label: "ALL" },
              { id: "chicken",  label: "CHICKEN" },
              { id: "burger",   label: "BURGERS" },
              { id: "combo",    label: "COMBOS" },
              { id: "side",     label: "SIDES" },
              { id: "dessert",  label: "DESSERTS" },
              { id: "drink",    label: "DRINKS" },
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => handleTabChange(tab.id)}
                className={`px-6 py-2 rounded-md font-bold whitespace-nowrap transition-colors border-2 cursor-pointer ${activeTab === tab.id ? "bg-[#242424] text-white border-[#242424]" : "border-[#242424] text-[#242424] hover:bg-gray-200"}`}
              >
                {tab.label}
              </button>
            ))}
          </div>

          <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3 md:gap-6">
            {filteredMenu.map((item) => (
              <MenuCard
                key={item.id}
                item={item}
                onAddToCart={(id, name) =>
                  checkBranchBeforeAction("ADD", { id, name })
                }
                onOpenModal={() => checkBranchBeforeAction("VIEW", item)}
              />
            ))}
          </div>
        </main>
      </div>

      {/* --- MOBILE CART STICKY BAR --- */}
      {totalItems > 0 && (
        <div
          className="md:hidden fixed bottom-0 left-0 right-0 bg-[#242424] p-4 flex justify-between items-center text-white z-40 border-t-4 border-[#e4002b] cursor-pointer"
          onClick={() => navigate("/order")}
        >
          <div>
            <div className="text-xs opacity-60 uppercase font-bold">
              {totalItems} Items
            </div>
            <div className="text-xl font-black text-[#e4002b]">
              ฿{totalPrice.toLocaleString()}.-
            </div>
          </div>
          <button className="bg-[#e4002b] px-6 py-2 rounded-full font-black text-sm font-['Bebas_Neue'] shadow-lg flex items-center gap-2 cursor-pointer">
            VIEW CART <ArrowRight size={16} />
          </button>
        </div>
      )}

      {/* Toast Noti */}
      <div
        className={`fixed bottom-8 right-8 bg-[#242424] text-white px-6 py-4 rounded-lg shadow-2xl border-l-4 border-[#e4002b] flex items-center gap-3 transition-all duration-300 z-60 ${toastMsg ? "translate-y-0 opacity-100" : "translate-y-10 opacity-0 pointer-events-none"}`}
      >
        <CheckCircle className="text-[#e4002b]" size={20} />
        <span className="font-bold">{toastMsg}</span>
      </div>

      {/* Product Modal */}
      <ProductModal
        isOpen={!!selectedItem}
        onClose={() => setSelectedItem(null)}
        item={selectedItem}
        onAddToCart={(id, name, qty) =>
          checkBranchBeforeAction("ADD", { id, name }, qty)
        }
      />

      {/* Cart Sidebar */}
      <div className="relative z-9998">
        <CartSidebar
          isOpen={isCartOpen}
          onClose={() => setIsCartOpen(false)}
          cartItems={cart}
          onUpdateQty={handleUpdateQty}
          onOpenLoginModal={() => setIsLoginModalOpen(true)} // ✅ ส่ง Props ตัวนี้เข้าไป
        />
      </div>

      {/* LoginModal */}
      <LoginModal
        isOpen={isLoginModalOpen}
        onClose={() => setIsLoginModalOpen(false)}
      />
    </div>
  );
};

export default MenuPage;

import React, { useContext,useEffect } from "react";
import { OrdersContext } from "../../context/ordersContext/OrdersContext";
import { PaymentContext } from "../../context/paymentContext";
import CheckoutSteps from "../../component/customer/CheckOutStep";
import OrderSummary from "../../component/customer/OrderSummary";
import { useLocation, useNavigate } from "react-router-dom";

export default function PaymentPage() {
  const { orderList } = useContext(OrdersContext);
  const { paymentState, setPaymentMethod, setAmount, setStatus } = useContext(PaymentContext);
  const location = useLocation();
  const navigate = useNavigate();
  const bookingData = location.state;

  const allCartItems = orderList
    ? orderList.flatMap((order) => order.List || order.orderList || [])
    : [];

  // Calculate totals
  const subTotal = allCartItems.reduce((sum, item) => sum + (item.price || 0) * item.quantity, 0);
  const tax = subTotal * 0.07;
  const netTotal = subTotal + tax;

  // Initialize payment amount when component loads
  useEffect(() => {
    if (netTotal > 0) {
      setAmount(netTotal);
    }
  }, [netTotal, setAmount]);

  // Redirect if no booking data
  useEffect(() => {
    if (!bookingData) {
      navigate("/booking");
    }
  }, [bookingData, navigate]);

  return (
    <div className="bg-[#eeeeee] min-h-screen py-10 font-['IBM_Plex_Sans_Thai'] text-[#242424]">
      <main className="container mx-auto px-4 max-w-6xl">
        <h1 className="font-['Bebas_Neue'] uppercase tracking-widest text-4xl mb-8 flex items-center gap-3 text-[#242424]">
          <span className="bg-[#e4002b] w-2 h-9 pt-12 rounded-full border-2 border-[#242424] shadow-[4px_4px_0_#242424]"></span>
          Checkout
        </h1>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
          <div className="lg:col-span-2 bg-white rounded-4xl border">
            <CheckoutSteps bookingData={bookingData} />
          </div>

          <div className="lg:col-span-1 bg-white rounded-4xl border p-6">
            <OrderSummary cartItems={allCartItems} bookingData={bookingData} />
          </div>
        </div>
      </main>
    </div>
  );
}
